import { REGEXP_ONLY_DIGITS } from "input-otp";
import {
  createContext,
  type FormEvent,
  type ReactNode,
  useCallback,
  useContext,
  useRef,
  useState,
} from "react";
import InputError from "@/components/input-error";
import PasswordInput from "@/components/password-input";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { InputOTP, InputOTPGroup, InputOTPSlot } from "@/components/ui/input-otp";
import { Label } from "@/components/ui/label";
import { Spinner } from "@/components/ui/spinner";
import { OTP_MAX_LENGTH } from "@/hooks/use-two-factor-auth";
import { type ConfirmationType, runConfirmAction } from "@/lib/confirm-action";

type ConfirmSensitiveAction = <T>(action: () => Promise<T>) => Promise<T>;

type ActionConfirmationContextValue = {
  confirmSensitiveAction: ConfirmSensitiveAction;
};

class ActionConfirmationCancelledError extends Error {
  constructor() {
    super("Action confirmation was cancelled.");
    this.name = "ActionConfirmationCancelledError";
  }
}

const ActionConfirmationContext = createContext<ActionConfirmationContextValue | null>(null);

type PendingConfirmation = {
  resolve: () => void;
  reject: (error: Error) => void;
};

const getCsrfHeader = (): Record<string, string> => {
  const token = document.querySelector<HTMLMetaElement>('meta[name="csrf-token"]')?.content;

  if (token) {
    return { "X-CSRF-TOKEN": token };
  }

  const cookie = document.cookie
    .split("; ")
    .find((value) => value.startsWith("XSRF-TOKEN="))
    ?.slice("XSRF-TOKEN=".length);

  return cookie ? { "X-XSRF-TOKEN": decodeURIComponent(cookie) } : {};
};

const getError = async (response: Response, field: "password" | "code"): Promise<string> => {
  try {
    const payload = await response.json();
    const fieldErrors = payload?.errors?.[field];

    if (Array.isArray(fieldErrors) && typeof fieldErrors[0] === "string") {
      return fieldErrors[0];
    }

    if (typeof payload?.message === "string") {
      return payload.message;
    }
  } catch {
    // Fall through to the generic message below.
  }

  return field === "password"
    ? "Unable to confirm your password."
    : "Unable to confirm your authentication code.";
};

const normalizeAuthenticationCode = (value: string): string => value.replace(/\D/g, "");

export function ActionConfirmationProvider({ children }: { children: ReactNode }) {
  const pendingConfirmation = useRef<PendingConfirmation | null>(null);
  const [confirmationType, setConfirmationType] = useState<ConfirmationType | null>(null);
  const [password, setPassword] = useState("");
  const [code, setCode] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [processing, setProcessing] = useState(false);

  const open = confirmationType !== null;
  const isTwoFactorConfirmation = confirmationType === "two-factor";

  const resetDialog = () => {
    setPassword("");
    setCode("");
    setError(null);
    setProcessing(false);
  };

  const requestConfirmation = useCallback((type: ConfirmationType): Promise<void> => {
    resetDialog();
    setConfirmationType(type);

    return new Promise((resolve, reject) => {
      pendingConfirmation.current = { resolve, reject };
    });
  }, []);

  const confirmSensitiveAction = useCallback<ConfirmSensitiveAction>(
    (action) => runConfirmAction(action, requestConfirmation),
    [requestConfirmation],
  );

  const closeDialog = () => {
    pendingConfirmation.current?.reject(new ActionConfirmationCancelledError());
    pendingConfirmation.current = null;
    setConfirmationType(null);
    resetDialog();
  };

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    if (!confirmationType) {
      return;
    }

    setProcessing(true);
    setError(null);

    const field = isTwoFactorConfirmation ? "code" : "password";
    const response = await fetch(
      isTwoFactorConfirmation ? "/auth/two-factor-authentication/confirm" : "/confirm-password",
      {
        method: "POST",
        headers: {
          Accept: "application/json",
          "Content-Type": "application/json",
          ...getCsrfHeader(),
        },
        credentials: "same-origin",
        body: JSON.stringify(isTwoFactorConfirmation ? { code } : { password }),
      },
    );

    if (!response.ok) {
      setError(await getError(response, field));
      setProcessing(false);

      return;
    }

    pendingConfirmation.current?.resolve();
    pendingConfirmation.current = null;
    setConfirmationType(null);
    resetDialog();
  };

  return (
    <ActionConfirmationContext.Provider value={{ confirmSensitiveAction }}>
      {children}

      <Dialog open={open} onOpenChange={(isOpen) => !isOpen && closeDialog()}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {isTwoFactorConfirmation ? "Confirm authentication code" : "Confirm password"}
            </DialogTitle>
            <DialogDescription>
              {isTwoFactorConfirmation
                ? "Enter the authentication code from your authenticator app to continue this action."
                : "Confirm your password to continue this action."}
            </DialogDescription>
          </DialogHeader>

          <form onSubmit={handleSubmit} className="grid gap-4">
            {isTwoFactorConfirmation ? (
              <div className="flex flex-col items-center justify-center gap-3 text-center">
                <Label htmlFor="confirm-action-code" className="sr-only">
                  Authentication code
                </Label>
                <InputOTP
                  id="confirm-action-code"
                  maxLength={OTP_MAX_LENGTH}
                  value={code}
                  onChange={(value) => setCode(normalizeAuthenticationCode(value))}
                  disabled={processing}
                  pattern={REGEXP_ONLY_DIGITS}
                  autoFocus
                >
                  <InputOTPGroup>
                    {Array.from({ length: OTP_MAX_LENGTH }).map((_, index) => (
                      <InputOTPSlot key={index} index={index} />
                    ))}
                  </InputOTPGroup>
                </InputOTP>
                <InputError message={error ?? undefined} />
              </div>
            ) : (
              <div className="grid gap-2">
                <Label htmlFor="confirm-action-password">Password</Label>
                <PasswordInput
                  id="confirm-action-password"
                  value={password}
                  onChange={(event) => setPassword(event.target.value)}
                  autoComplete="current-password"
                  autoFocus
                  required
                />
                <InputError message={error ?? undefined} />
              </div>
            )}

            <DialogFooter>
              <Button type="button" variant="outline" onClick={closeDialog}>
                Cancel
              </Button>
              <Button
                type="submit"
                disabled={
                  processing ||
                  (isTwoFactorConfirmation ? code.length !== OTP_MAX_LENGTH : password.length === 0)
                }
              >
                {processing && <Spinner />}
                {isTwoFactorConfirmation ? "Confirm code" : "Confirm password"}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>
    </ActionConfirmationContext.Provider>
  );
}

export function useActionConfirmation() {
  const context = useContext(ActionConfirmationContext);

  if (!context) {
    throw new Error("useActionConfirmation must be used within ActionConfirmationProvider.");
  }

  return context;
}
